#include<bits/stdc++.h>
using namespace std;
int a[100010],n,d1[100010],d2[100010],d3[100010];
int max1[2],max2[2],maxd[2][100010];
vector<int> mp[100010];
int ans;
void dfs(int x,int fa=-1)
{
    maxd[a[x]][x]=0;
    maxd[1-a[x]][x]=-1e9;
    for(int i:mp[x])if(i!=fa)
    {
        dfs(i,x);
        maxd[0][x]=max(maxd[0][x],maxd[0][i]+1);
        maxd[1][x]=max(maxd[1][x],maxd[1][i]+1);
        ans=max(ans,maxd[1-a[x]][i]+1);
        // if(maxd[1-a[x]][i]+1==4)
        // {
        //     printf("maxd[%d][%d]+1==4\n",1-a[x],i);
        // }
    }
    // printf("maxd[%d][0]=%d\nmaxd[%d][1]=%d\n",x,maxd[0][x],x,maxd[1][x]);
    int max0=-1e9,max1=-1e9,first=1;
    for(int i:mp[x])if(i!=fa)
    {
        if(!first)
        {
            ans=max({ans,max0+maxd[1][i]+2,max1+maxd[0][i]+2});
        }
        else
        {
            first=0;
        }
        max0=max(max0,maxd[0][i]);
        max1=max(max1,maxd[1][i]);
    }
    reverse(mp[x].begin(),mp[x].end());
    max0=-1e9,max1=-1e9;
    first=1;
    for(int i:mp[x])if(i!=fa)
    {
        if(!first)
        {
            ans=max({ans,max0+maxd[1][i]+2,max1+maxd[0][i]+2});
        }
        else
        {
            first=0;
        }
        max0=max(max0,maxd[0][i]);
        max1=max(max1,maxd[1][i]);
    }
    reverse(mp[x].begin(),mp[x].end());
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs(1);
    printf("%d\n",ans);
    return 0;
}
